SELECT AVG(environmental_impact_value) AS average_environmental_impact
FROM resource_consumption
WHERE year >= 2015;

SELECT sustainability_score, total_cost
FROM sustainability_metrics
WHERE year = 2020;

SELECT SUM(total_cost) AS total_annual_cost
FROM consumption_reports
WHERE year = 2020;

SELECT y.year, sm.sustainability_score
FROM years y
JOIN sustainability_metrics sm ON y.year = sm.year;

SELECT total_consumption, total_capacity 
FROM consumption_reports
WHERE year = 2023;

SELECT DISTINCT resource_id
FROM resource_consumption
WHERE year = 2020;

SELECT consumption_per_unit
FROM resource_consumption
WHERE resource_id = 1 AND year = 2023;

SELECT year, SUM(cost) AS total_cost
FROM resource_consumption
GROUP BY year;

SELECT total_consumption
FROM consumption_reports
WHERE year = 2022;
